\chapter{Introduction and Safety Protocols}
\section{Scope and Purpose}
This manual provides detailed, step-by-step instructions for the safe extraction, containment, and initial processing of Cesium-137 (\ch{Cs^{137}}) source pellets from obsolete or decommissioned nucleonic point level sensors and gauges. These devices are commonly used in industrial settings for density, level, and interface measurement. The procedure is intended for trained personnel in a controlled radiochemical or nuclear handling facility.

\section{Fundamental Safety Principles}
\begin{itemize}
    \item \textbf{ALARA (As Low As Reasonably Achievable):} Minimize time of exposure, maximize distance from the source, and utilize appropriate shielding at all times.
    \item \textbf{Containment:} Prevent the dispersal of radioactive material. Assume the source capsule integrity is compromised until verified.
    \item \textbf{Personal Protection:} Mandatory use of:
    \begin{itemize}
        \item Full-body anti-contamination suits (Tyvek or equivalent).
        \item Double nitrile gloves with tape seals.
        \item Respiratory protection (PAPR with HEPA filters or supplied air) for any operation where dust or aerosols could be generated.
        \item Thermoluminescent dosimeters (TLDs) and electronic personal dosimeters (EPDs).
    \end{itemize}
    \item \textbf{Engineering Controls:} All procedures must be conducted within a certified:
    \begin{itemize}
        \item Class III Hot Cell \textbf{OR}
        \item Glovebox maintained under negative pressure with HEPA filtration \textbf{OR}
        \item Shielded Laminar Flow Hood with \SI{5}{cm} lead-equivalent shielding.
    \end{itemize}
    \item \textbf{Emergency Protocols:} Have spill kits, remote handling tools, and decontamination solutions (e.g., EDTA for cesium) readily available. Establish a clear evacuation and notification plan.
\end{itemize}

\chapter{Pre-Extraction Procedures}
\section{Material Identification and Assessment}
\begin{enumerate}
    \item \textbf{Device Identification:} Confirm the device is a nucleonic level sensor. Common models include ``point'' or ``switch'' level gauges containing a small, sealed \ch{Cs^{137}} source (typically \SIrange{10}{100}{\milli\curie} or \SIrange{0.37}{3.7}{\giga\becquerel}).
    \item \textbf{Radiation Survey:} Using a calibrated gamma survey meter (e.g., NaI scintillator), map the external dose rate from the device. Expect rates from \SIrange{0.1}{10}{\milli\sievert\per\hour} at \SI{30}{\centi\meter}. Identify the ``hot spot'' where the source is located.
    \item \textbf{Physical Inspection:} Visually inspect (via camera if high dose) the sensor housing. Identify fasteners (bolts, screws, welds). Determine if the source capsule is housed in a rotating shutter mechanism or a fixed collimator.
    \item \textbf{Containment Preparation:} Place the entire device inside the primary containment (hot cell or glovebox). Perform a final contamination swipe test on the exterior before sealing.
\end{enumerate}

\section{Tool and Equipment Preparation}
\begin{itemize}
    \item \textbf{Remote Manipulators:} Master-slave manipulators or long-handled (\SI{>1}{\meter}) tools.
    \item \textbf{Cutting/Disassembly Tools:} Pneumatic or electric drills, rotary tools with carbide bits, and hacksaws—all operable remotely or with extended handles.
    \item \textbf{Containers:}
    \begin{itemize}
        \item \textbf{Primary:} Small, shielded ``pig'' container made of lead or depleted uranium, with an inner stainless steel or aluminum canister.
        \item \textbf{Secondary:} Sealed, labeled plastic bag for contaminated tooling and waste.
    \end{itemize}
    \item \textbf{Monitoring:} Install a continuous air monitor (CAM) inside the containment. Have a handheld alpha/beta/gamma probe ready inside the workspace.
\end{itemize}

\chapter{Source Extraction Procedure}
\section{Housing Deconstruction}
\begin{enumerate}
    \item \textbf{Fixation:} Secure the sensor body in a vise or clamping system inside the containment.
    \item \textbf{Shutter/Shield Removal:} If present, carefully unbolt or drill out the pins holding the external tungsten or lead shutter. Set this heavily shielded component aside.
    \item \textbf{Housing Breach:} Using a drill, create pilot holes around the perimeter of the source housing compartment. Connect the holes using a rotary cutting tool or small saw to remove a section of the outer casing. \textbf{Constant suction} via a HEPA-filtered vacuum must be applied at the cutting point to capture aerosols and particulates.
    \item \textbf{Internal Exposure:} Once breached, immediately survey the interior with the handheld probe. Dose rates will increase significantly.
\end{enumerate}

\section{Capsule Identification and Handling}
\begin{enumerate}
    \item \textbf{Locate the Capsule:} The \ch{Cs^{137}} source is typically a sintered ceramic (cesium chloride or glass matrix) pellet, doubly encapsulated in stainless steel welded capsules. It may be \SIrange{5}{10}{\milli\meter} in diameter and length.
    \item \textbf{Mechanical Disengagement:} The capsule is often held in place by a set-screw or a spring-loaded bracket. Use remote tools to loosen the fastener or compress the spring.
    \item \textbf{Extraction:} Using long-handled forceps or a vacuum pickup tool (with HEPA filter in-line), gently lift the source capsule straight out of its seating.
    \item \textbf{Immediate Storage:} In one smooth motion, transfer the capsule to the open primary container (the ``pig''). Secure the capsule inside the inner canister using foam or a fitted holder to prevent movement.
    \item \textbf{Seal Primary Container:} Immediately close and latch the lid of the inner canister, then close and lock the outer shielded lid of the pig.
\end{enumerate}

\section{Post-Extraction Containment Verification}
\begin{enumerate}
    \item \textbf{Survey the Pig:} Conduct a radiation survey of the sealed pig. The surface dose rate should be dramatically lower than during extraction, confirming the shielding is effective.
    \item \textbf{Contamination Check:} Thoroughly survey the interior of the dismantled sensor, all tools, and the containment workspace with an alpha/beta/gamma probe. Pay special attention to seams and corners.
    \item \textbf{Decontamination:} If contamination is found (\SI{>0.1}{\becquerel\per\centi\meter\squared}), use damp wipes with a chelating agent solution (e.g., \SI{0.1}{\molar} EDTA) to clean surfaces. All wipes and wash solutions become radioactive waste.
    \item \textbf{Waste Packaging:} Place all dismantled sensor parts, used tools, gloves, wipes, and filters into the secondary sealed plastic bags. Label clearly: ``LLW - Contaminated with \ch{Cs^{137}}''.
\end{enumerate}

\chapter{Post-Extraction Processing and Storage}
\section{Source Characterization}
\begin{enumerate}
    \item \textbf{Assay:} In a separate, secure assay cell, use a High-Purity Germanium (HPGe) Gamma Spectrometer to confirm the isotope (\ch{Cs^{137}} via the \SI{661.7}{\kilo\electronvolt} photopeak) and quantify the activity.
    \item \textbf{Leak Test:} Perform a wipe test on the exterior of the primary capsule. If contamination is detected, the capsule integrity is breached. It must then be immediately placed into an additional, sealed \textbf{overpack} container.
\end{enumerate}

\section{Interim Storage and Disposition}
\begin{itemize}
    \item \textbf{Storage:} The sealed pig must be stored in a designated radioactive materials storage area, with proper shielding (lead bricks) and clear labeling.
    \item \textbf{Disposition Options:}
    \begin{itemize}
        \item \textbf{Reuse:} If activity is sufficient and capsule integrity is certified, the source can be repackaged for use in calibration instruments or research.
        \item \textbf{Decay Storage:} For lower-activity sources, store for \SI{10}{half-lives} (\~{}300 years for \ch{Cs^{137}}) to allow for significant decay before disposal as low-level waste. \textbf{This is impractical.}
        \item \textbf{Reprocessing:} The source can be transferred to a licensed fuel cycle facility for dissolution and isotopic separation. Cesium-137 can be used in radioisotope thermoelectric generators (RTGs) or sterilizers.
        \item \textbf{Disposal:} Ultimate disposal as sealed source requires a licensed deep geological repository for intermediate-level waste.
    \end{itemize}
\end{itemize}

\chapter{Regulatory and Documentation Framework}
\section{Mandatory Documentation}
\begin{itemize}
    \item Radiation Work Permit (RWP) for the procedure.
    \item Pre- and Post-job radiation survey logs.
    \item Waste manifest and tracking forms (IAEA-style).
    \item Chain of custody documents for the extracted source.
    \item Incident report (if any deviation or contamination event occurred).
\end{itemize}

\section{Regulatory Compliance}
This procedure must comply with:
\begin{itemize}
    \item National Nuclear Regulator (NNR) regulations for sealed source handling.
    \item IAEA Safety Standards Series (SSG-12, SSG-34).
    \item Local radiation protection ordinances.
\end{itemize}

\appendix
\chapter{Chemical and Physical Properties of Cesium-137}
\begin{itemize}
    \item \textbf{Half-life:} \SI{30.08}{years}
    \item \textbf{Decay Mode:} Beta-minus (\beta^-) to metastable Barium-137m (\ch{Ba^{137m}}), which subsequently decays by gamma emission (\SI{661.7}{\kilo\electronvolt}).
    \item \textbf{Specific Activity:} \SI{3.215}{\tera\becquerel\per\gram} (\SI{86.9}{\curie\per\gram}).
    \item \textbf{Biological Hazard:} Soluble cesium compounds distribute uniformly throughout the body, irradiating soft tissues. It is a potent gamma emitter.
\end{itemize}

