      timestamp: Date.now(),
      blob: blob,
      url: await getCurrentTabUrl(),
      title: await getCurrentTabTitle()
    };

    await storeData('screenshots', screenshotData);
    videoTrack.stop();
  } catch (error) {
    console.log('Screenshot capture failed:', error);
  }
}

